home-extract.expression:
(function(){
  function textByTestId(id){ var el=document.querySelector('[data-testid="'+id+'"]'); return el?((el.textContent||'').trim()||null):null; }
  function linesOf(el){ return ((el && (el.innerText || el.textContent)) || '').split(String.fromCharCode(10)).map(function(s){return s.trim();}).filter(Boolean); }
  function bestRow(label, pattern){ var re=new RegExp(pattern); var best=null; var nodes=document.querySelectorAll('div,section,article,button,[data-testid]'); for(var i=0;i<nodes.length;i++){ var lines=linesOf(nodes[i]); if(lines.indexOf(label)===-1) continue; var matches=lines.filter(function(line){ return line!==label && re.test(line); }); if(!matches.length) continue; if(lines.length>14) continue; if(!best || lines.length<best.lines.length){ best={lines:lines, value:matches[matches.length-1]}; } } return best; }
  function rowValue(label, pattern){ var best=bestRow(label, pattern); return best?best.value:null; }
  return JSON.stringify({screen:'home',totalBalance:rowValue('Total balance','^\$'),pnl:textByTestId('perps-balance-dropdown-pnl')});
})()

